function ProductCard({ product }) {
  return (
    <div className="product-card">
      <h3>{product.name}</h3>

      <p>{product.description}</p>

      <h2>
        ₹{product.price}
      </h2>

      <span>
        {product.category}
      </span>

      <button>
        Add To Cart
      </button>
    </div>
  );
}

export default ProductCard;
